import scala.collection.mutable.{ArrayBuffer, HashMap}

def solve(n: Long, edges: Array[Array[Long]], label: String): Long = {
  val graph = Array.fill(n.toInt)(ArrayBuffer[Int]())
  for (edge <- edges) {
    val u = edge(0).toInt
    val v = edge(1).toInt
    graph(u) += v
    graph(v) += u
  }

  var maxLen = 1L

  def dfs(node: Int, mask: Int): Int = {
    val newMask = mask | (1 << node)
    var maxSub = 0

    for (neighbor <- graph(node)) {
      if ((newMask & (1 << neighbor)) == 0) {
        val currentMax = dfs(neighbor, newMask)
        if (currentMax > maxSub) {
          maxSub = currentMax
        }
      }
    }

    val chars = (0 until n.toInt).filter(i => (newMask & (1 << i)) != 0).map(label.charAt(_))
    val freq = HashMap[Char, Int]()
    for (c <- chars) {
      freq.put(c, freq.getOrElse(c, 0) + 1)
    }
    var oddCount = 0
    for ((_, count) <- freq) {
      if (count % 2 == 1) {
        oddCount += 1
      }
    }
    val currentLen = chars.length
    if (oddCount <= 1) {
      if (currentLen > maxLen) {
        maxLen = currentLen
      }
      currentLen
    } else {
      if (maxSub > 1) maxSub else 1
    }
  }

  for (start <- 0 until n.toInt) {
    dfs(start, 0)
  }

  maxLen
}
