def solve(n: Long, edges: Array[Array[Long]], label: String): Long = {
    val graph = Array.fill(n.toInt)(ArrayBuffer[Int]())
    for (edge <- edges) {
        val u = edge(0).toInt
        val v = edge(1).toInt
        graph(u) += v
        graph(v) += u
    }

    var maxLen = 1L

    val memo = HashMap[(Int, Int), Long]()

    def dfs(node: Int, mask: Int): Long = {
        if (memo.contains((node, mask))) return memo((node, mask))
        val newMask = mask | (1 << node)
        var currentMax = 0L
        for (neighbor <- graph(node)) {
            if ((newMask & (1 << neighbor)) == 0) {
                val neighborMax = dfs(neighbor, newMask)
                if (neighborMax > currentMax) {
                    currentMax = neighborMax
                }
            }
        }

        val chars = new StringBuilder()
        for (i <- 0 until n.toInt) {
            if ((newMask & (1 << i)) != 0) {
                chars += label(i)
            }
        }

        val freq = HashMap[Char, Int]()
        for (c <- chars.toString()) {
            freq.put(c, freq.getOrElse(c, 0) + 1)
        }

        var oddCount = 0
        for ((_, count) <- freq) {
            if (count % 2 == 1) {
                oddCount += 1
            }
        }

        val currentLen = chars.length.toLong
        val result = 
            if (oddCount <= 1) {
                if (currentLen > maxLen) {
                    maxLen = currentLen
                }
                math.max(currentLen, currentMax)
            } else {
                if (currentMax > 1) currentMax else 1L
            }
        memo.put((node, mask), result)
        result
    }

    for (start <- 0 until n.toInt) {
        dfs(start, 0)
    }

    maxLen
